mapper.select:
SELECT id, title, business_type, method, request_method, oper_name, oper_url, oper_ip, oper_location, status, error_msg, oper_time, trace_id FROM sys_oper_log
AND title LIKE CONCAT('%', #{query.title}, '%')
AND oper_name LIKE CONCAT('%', #{query.operName}, '%')
AND business_type = #{query.businessType}
AND status = #{query.status}
ORDER BY oper_time DESC
